#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <string>
#include "cJSON.h"
#include "lodepng.h"

static char* read_file(const char* path, size_t* len) {
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", path); exit(1); }
    fseek(f, 0, SEEK_END);
    long n = ftell(f);
    fseek(f, 0, SEEK_SET);
    char* buf = (char*)malloc(n + 1);
    if (fread(buf, 1, n, f) != (size_t)n) { fprintf(stderr, "read error\n"); exit(1); }
    buf[n] = 0;
    fclose(f);
    if (len) *len = (size_t)n;
    return buf;
}

// Read a JSON array of doubles into out (flattened, row-major for 2D).
static void read_array(cJSON* node, std::vector<double>& out) {
    if (cJSON_IsArray(node)) {
        cJSON* child = node->child;
        while (child) {
            read_array(child, out);
            child = child->next;
        }
    } else if (cJSON_IsNumber(node)) {
        out.push_back(node->valuedouble);
    }
}

static void get_layer(cJSON* root, const char* name,
                      std::vector<double>& w, std::vector<double>& b) {
    cJSON* layer = cJSON_GetObjectItemCaseSensitive(root, name);
    if (!layer) { fprintf(stderr, "missing layer %s\n", name); exit(1); }
    read_array(cJSON_GetObjectItemCaseSensitive(layer, "weight"), w);
    read_array(cJSON_GetObjectItemCaseSensitive(layer, "bias"), b);
}

// y = W x + b, W is (out x in) row-major, then optional ReLU.
static std::vector<double> linear(const std::vector<double>& W,
                                  const std::vector<double>& b,
                                  const std::vector<double>& x,
                                  bool relu) {
    size_t out = b.size();
    size_t in = x.size();
    std::vector<double> y(out);
    for (size_t o = 0; o < out; ++o) {
        double acc = b[o];
        const double* wr = &W[o * in];
        for (size_t i = 0; i < in; ++i) acc += wr[i] * x[i];
        if (relu && acc < 0) acc = 0;
        y[o] = acc;
    }
    return y;
}

int main(int argc, char** argv) {
    if (argc < 3) {
        fprintf(stderr, "usage: %s weights.json image.png\n", argv[0]);
        return 1;
    }

    // Load weights.
    size_t jlen;
    char* jtxt = read_file(argv[1], &jlen);
    cJSON* root = cJSON_Parse(jtxt);
    if (!root) { fprintf(stderr, "json parse error\n"); return 1; }

    cJSON* mn = cJSON_GetObjectItemCaseSensitive(root, "mean");
    cJSON* st = cJSON_GetObjectItemCaseSensitive(root, "std");
    double mean = mn ? mn->valuedouble : 0.1307;
    double stdv = st ? st->valuedouble : 0.3081;

    std::vector<double> w1, b1, w2, b2, w3, b3;
    get_layer(root, "input_layer", w1, b1);
    get_layer(root, "hidden_layer", w2, b2);
    get_layer(root, "output_layer", w3, b3);

    // Load image as 8-bit grayscale.
    std::vector<unsigned char> img;
    unsigned width, height;
    unsigned err = lodepng::decode(img, width, height, argv[2], LCT_GREY, 8);
    if (err) { fprintf(stderr, "png error: %s\n", lodepng_error_text(err)); return 1; }

    size_t npix = (size_t)width * height;
    std::vector<double> x(npix);
    for (size_t i = 0; i < npix; ++i)
        x[i] = ((img[i] / 255.0) - mean) / stdv;

    std::vector<double> h1 = linear(w1, b1, x, true);
    std::vector<double> h2 = linear(w2, b2, h1, true);
    std::vector<double> logits = linear(w3, b3, h2, false);

    int best = 0;
    for (size_t i = 1; i < logits.size(); ++i)
        if (logits[i] > logits[best]) best = (int)i;

    printf("%d\n", best);

    cJSON_Delete(root);
    free(jtxt);
    return 0;
}
